import React, { useRef, useState, useEffect } from 'react';
import { graphql } from 'gatsby';
import styled, { withTheme } from 'styled-components';
import Layout from '../components/Layouts/Layout';
import Card from '../components/Card';
import routes from '../config/web/routes';
import { BigTitle } from '../components/Type/Titles';
import CardGrid from '../components/CardGrid/CardGrid';

export const query = graphql`
  query IndexQuery {
    allSitePage {
      edges {
        node {
          path
        }
      }
    }
  }
`;

const ContentWrap = styled.div`
  margin: auto;
  padding-top: 2vh;
  text-align: center;
  height: inherit;
  @media screen and (min-width: ${props => props.theme.screens.md}) {
    display: flex;
    justify-content: center;
  }
`;

const Panel = styled.div`
  width: 100%;
  padding: 1em;
  display: block;
  @media screen and (min-width: ${props => props.theme.screens.md}) {
    display: inline-flex;
    width: 50%;
  }
`;

const MainTitle = styled(BigTitle)`
  @media screen and (min-width: ${props => props.theme.screens.md}) {
    position: absolute;
  }
  bottom: 1em;
  text-align: left;
`;
const Index = ({ data }) => {
  return (
    <Layout>
      <ContentWrap>
        <Panel>
          <MainTitle>
            Hi! 👋 <br /> I'm Diana.
          </MainTitle>
        </Panel>
        <Panel style={{ padding: 'unset' }}>
          <CardGrid items={routes} />
        </Panel>
      </ContentWrap>
    </Layout>
  );
};
export default Index;
